#include "game/save/SaveGameProfile.h"
#include <fstream>
#include <sstream>
namespace fw {
bool SaveGameProfile::SaveToFile(const std::string& path) const{ std::ofstream out(path); if(!out.is_open()) return false; out<<"region="<<currentRegion<<"\n"; out<<"health="<<playerHealth<<"\n"; out<<"maxHealth="<<playerMaxHealth<<"\n"; out<<"pos="<<playerPosition.x<<","<<playerPosition.y<<","<<playerPosition.z<<"\n"; out<<"gold="<<inventory.gold<<"\n"; out<<"equippedWeaponId="<<inventory.equippedWeaponId<<"\n"; out<<"equippedArmorId="<<inventory.equippedArmorId<<"\n"; for(const auto& item:inventory.items) out<<"item="<<item<<"\n"; for(const auto& q:quests) out<<"quest="<<q.id<<","<<static_cast<int>(q.state)<<"\n"; return true; }
bool SaveGameProfile::LoadFromFile(const std::string& path){ std::ifstream in(path); if(!in.is_open()){ ResetToDefaults(); return false; } ResetToDefaults(); std::string line; while(std::getline(in,line)){ if(line.rfind("region=",0)==0) currentRegion=line.substr(7); else if(line.rfind("health=",0)==0) playerHealth=std::stoi(line.substr(7)); else if(line.rfind("maxHealth=",0)==0) playerMaxHealth=std::stoi(line.substr(10)); else if(line.rfind("gold=",0)==0) inventory.gold=std::stoi(line.substr(5)); else if(line.rfind("equippedWeaponId=",0)==0) inventory.equippedWeaponId=line.substr(17); else if(line.rfind("equippedArmorId=",0)==0) inventory.equippedArmorId=line.substr(16); else if(line.rfind("item=",0)==0) inventory.items.push_back(line.substr(5)); else if(line.rfind("pos=",0)==0){ std::stringstream ss(line.substr(4)); std::string part; if(std::getline(ss,part,',')) playerPosition.x=std::stof(part); if(std::getline(ss,part,',')) playerPosition.y=std::stof(part); if(std::getline(ss,part,',')) playerPosition.z=std::stof(part);} else if(line.rfind("quest=",0)==0){ QuestEntry q{}; std::stringstream ss(line.substr(6)); std::string idPart,statePart; if(std::getline(ss,idPart,',')) q.id=idPart; if(std::getline(ss,statePart,',')) q.state=static_cast<QuestProgressState>(std::stoi(statePart)); quests.push_back(q);} } return true; }
void SaveGameProfile::ResetToDefaults(){ currentRegion="village_region"; playerHealth=100; playerMaxHealth=100; playerPosition={0.0f,1.0f,0.0f}; inventory.Clear(); quests.clear(); }
}
